import java.util.*;

public class Solution {

    /**
     * Helper class to represent an edge connection in the graph.
     */
    static class EdgeInfo {
        int v;
        boolean isHeavy;

        EdgeInfo(int v, boolean isHeavy) {
            this.v = v;
            this.isHeavy = isHeavy;
        }
    }

    /**
     * Checks if 'target' can be reached from 'source' using at most 'k' heavy edges
     * when the threshold is 'threshold'.
     * This uses Dijkstra's algorithm where the distance is the count of heavy edges.
     * 
     * @param n The number of nodes.
     * @param edges The list of all edges [u, v, w].
     * @param source The starting node.
     * @param target The destination node.
     * @param k The maximum allowed heavy edges.
     * @param threshold The current threshold value.
     * @return True if a valid path exists, false otherwise.
     */
    private static boolean canReach(int n, int[][] edges, int source, int target, int k, int threshold) {
        if (source == target) return true;

        // Adjacency list: adj[u] = List of EdgeInfo {v: neighbor, isHeavy: boolean}
        List<List<EdgeInfo>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int w = edge[2];
            boolean isHeavy = w > threshold;

            // Undirected graph
            adj.get(u).add(new EdgeInfo(v, isHeavy));
            adj.get(v).add(new EdgeInfo(u, isHeavy));
        }

        // dist[i] = minimum number of heavy edges to reach node i from source
        // Initialize with k + 1 (or infinity, since max heavy edges is k)
        int[] dist = new int[n];
        Arrays.fill(dist, k + 1);

        // Priority Queue stores {heavy_count, node}. We prioritize lower heavy_count.
        // Custom comparator: compare based on heavy_count (the first element in the array).
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));

        dist[source] = 0;
        pq.offer(new int[]{0, source}); // {heavy_count, node}

        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            int d = current[0];
            int u = current[1];

            if (d > dist[u]) {
                continue;
            }

            if (u == target) {
                // Since Dijkstra processes in increasing order of distance, 
                // the first time we extract target, d is the minimum heavy count.
                return d <= k;
            }

            for (EdgeInfo edge : adj.get(u)) {
                int v = edge.v;
                // Cost to move to v is 1 if the edge is heavy, 0 otherwise
                int edgeCost = edge.isHeavy ? 1 : 0;
                int newDist = d + edgeCost;

                if (newDist <= k && newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.offer(new int[]{newDist, v});
                }
            }
        }

        return dist[target] <= k;
    }

    public static long solve(long n, long[][] edges, long source, long target, long k) {
        if (source == target) return 0;

        int N = (int) n;
        int S = (int) source;
        int T = (int) target;
        int K = (int) k;

        // 1. Collect all unique edge weights to form the search space for threshold
        Set<Integer> uniqueWeights = new HashSet<>();
        uniqueWeights.add(0); // Threshold can be 0
        for (long[] edge : edges) {
            uniqueWeights.add((int) edge[2]);
        }

        // Sort the potential thresholds in ascending order
        List<Integer> sortedThresholds = new ArrayList<>(uniqueWeights);
        Collections.sort(sortedThresholds);

        // 2. Linear Scan on sorted thresholds
        for (int threshold : sortedThresholds) {
            if (canReach(N, (int[][])edges, S, T, K, threshold)) {
                return threshold;
            }
        }

        // 3. If no threshold works
        return -1;
    }
}
