import java.util.*;

class Solution {
    /**
     * Checks if the target is reachable from the source using at most k heavy edges
     * when the threshold is given.
     * Uses a Dijkstra-like approach where the cost is the number of heavy edges.
     * 
     * @param n Number of nodes.
     * @param edges List of all edges.
     * @param source Starting node.
     * @param target Destination node.
     * @param k Maximum allowed heavy edges.
     * @param threshold The weight threshold.
     * @return True if reachable with <= k heavy edges, false otherwise.
     */
    private boolean canReach(int n, List<int[]> edges, int source, int target, int k, int threshold) {
        // Adjacency list: stores {neighbor, isHeavy}
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            int w = edge[2];
            boolean isHeavy = w > threshold;

            // Store {neighbor, isHeavy (as 1 or 0)}
            adj.get(u).add(new int[]{v, isHeavy ? 1 : 0});
            adj.get(v).add(new int[]{u, isHeavy ? 1 : 0});
        }

        // dist[i] = minimum number of heavy edges to reach node i from source
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);

        // Priority Queue stores [heavy_count, node]
        // We prioritize lower heavy_count.
        // PriorityQueue stores int[] where element[0] is heavy_count and element[1] is node.
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));

        dist[source] = 0;
        pq.offer(new int[]{0, source});

        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            int d = current[0]; // heavy_count
            int u = current[1]; // node

            if (d > dist[u]) {
                continue;
            }

            if (u == target) {
                return d <= k; // Reached target, and since Dijkstra ensures minimal d, we are done.
            }

            for (int[] edge : adj.get(u)) {
                int v = edge[0];
                int edgeCost = edge[1]; // 1 if heavy, 0 if light
                int newDist = d + edgeCost;

                if (newDist <= k && newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.offer(new int[]{newDist, v});
                }
            }
        }

        return dist[target] <= k;
    }

    public long solve(long n, long[][] edges, long source, long target, long k) {
        if (source == target) return 0;

        int N = (int) n;
        int S = (int) source;
        int T = (int) target;
        int K = (int) k;

        // Convert long[][] edges to list of int[] for easier iteration in helper
        List<int[]> edgeList = new ArrayList<>();
        Set<Integer> uniqueWeightsSet = new HashSet<>();
        uniqueWeightsSet.add(0); // Threshold can be 0

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];
            edgeList.add(new int[]{u, v, w});
