const solve = (n, edges, source, target, k) => {
    if (source === target) return 0;

    // 1. Collect all unique edge weights to form the search space for threshold
    let uniqueWeights = new Set([0]); // Threshold can be 0
    for (const [, , w] of edges) {
        uniqueWeights.add(w);
    }

    // Sort the potential thresholds in ascending order
    const sortedThresholds = Array.from(uniqueWeights).sort((a, b) => a - b);

    /**
     * Check function: Can we reach 'target' from 'source' using at most 'k' heavy edges
     * when the threshold is 'threshold'?
     * This is a shortest path problem where the 'cost' is the number of heavy edges.
     * We use a modified Dijkstra/BFS approach.
     * State: [node, heavy_edges_count]
     * Distance: Minimum heavy_edges_count to reach a node.
     * Since we are minimizing heavy edges (cost 0 or 1), 0-1 BFS (Deque based) is efficient, 
     * but a standard Dijkstra using a priority queue is robust.
     * Here, since the "cost" (heavy edge count) is small (0 or 1), a simple BFS/Dijkstra modification works well.
     * We will use a variation of Dijkstra where the 'distance' is the number of heavy edges.
     * 
     * @param {number} threshold
     * @returns {boolean}
     */
    const canReach = (threshold) => {
        // Adjacency list: adj[u] = [{v: neighbor, weight: w, isHeavy: boolean}]
        const adj = Array(n).fill(0).map(() => []);
        for (const [u, v, w] of edges) {
            const isHeavy = w > threshold;
            adj[u].push({ v: v, isHeavy: isHeavy });
            adj[v].push({ v: u, isHeavy: isHeavy });
        }

        // dist[i] = minimum number of heavy edges to reach node i from source
        const dist = Array(n).fill(Infinity);

        // Priority Queue stores [heavy_count, node]
        // We prioritize lower heavy_count.
        const pq = [[0, source]]; 
        dist[source] = 0;

        while (pq.length > 0) {
            // Simulate Priority Queue: find minimum heavy_count element
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > dist[u]) {
                continue;
            }

            if (u === target) {
                return d <= k;
            }

            for (const edge of adj[u]) {
                const v = edge.v;
                // Cost to move to v is 1 if the edge is heavy, 0 otherwise
                const edgeCost = edge.isHeavy ? 1 : 0;
                const newDist = d + edgeCost;

                if (newDist <= k && newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.push([newDist, v]);
                }
            }
        }

        return dist[target] <= k;
    };

    // 2. Binary Search or Linear Scan on sorted thresholds
    // Since we are looking for the MINIMUM threshold, a linear scan over sorted thresholds is simpler 
    // and fast enough given the constraints (O(E log E) for sorting + O(W * (E log N)), where W is number of unique weights).
    // W <= E+1, E <= 1000. E * (E log N) is acceptable.

    for (const threshold of sortedThresholds) {
        if (canReach(threshold)) {
            return threshold;
        }
    }

    // 3. If no threshold works (including the maximum possible weight)
    return -1;
};
